import { Component, OnDestroy, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ReactiveFormsModule, FormArray, FormBuilder, Validators } from '@angular/forms';
import { ActivatedRoute, Router, RouterModule } from '@angular/router';
import { Subject, startWith, takeUntil } from 'rxjs';
import { Invoice, RemiseType } from '../../models/invoice';
import { InvoiceLine } from '../../models/invoice-line';
import { InvoiceCalcService, InvoiceTotals } from '../../services/invoice-calc.service';
import { InvoiceStoreService } from '../../services/invoice-store.service';

@Component({
  selector: 'app-invoice-form',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule, RouterModule],
  templateUrl: './invoice-form.component.html',
  styleUrls: ['./invoice-form.component.css']
})
export class InvoiceFormComponent implements OnInit, OnDestroy {
  private readonly destroy$ = new Subject<void>();

  form = this.fb.group({
    numero: ['', Validators.required],
    date: ['', Validators.required],
    client: this.fb.group({
      nom: ['', Validators.required],
      adresse: ['', Validators.required],
      tel: ['', Validators.required],
      mf: [''],
      email: ['', Validators.email]
    }),
    lignes: this.fb.array([]),
    remiseType: ['montant' as RemiseType],
    remiseValue: [0],
    remiseAvantTVA: [true],
    notes: [''],
    conditions: ['']
  });

  totals: InvoiceTotals = {
    totalHT: 0,
    totalTVA: 0,
    totalTTC: 0,
    remise: 0,
    totalHTApresRemise: 0,
    totalTVAApresRemise: 0
  };

  isEdit = false;
  numeroConflict = false;
  private currentId: string | null = null;

  constructor(
    private fb: FormBuilder,
    private store: InvoiceStoreService,
    public calc: InvoiceCalcService,
    private route: ActivatedRoute,
    private router: Router
  ) {}

  get lignes(): FormArray {
    return this.form.get('lignes') as FormArray;
  }

  async ngOnInit(): Promise<void> {
    await this.store.load();

    const id = this.route.snapshot.paramMap.get('id');
    if (id) {
      this.isEdit = true;
      const invoice = await this.store.getById(id);
      if (!invoice) {
        this.router.navigate(['/invoices']);
        return;
      }
      this.currentId = invoice.id;
      this.form.patchValue({
        numero: invoice.numero,
        date: invoice.date,
        client: invoice.client,
        remiseType: invoice.remiseType ?? 'montant',
        remiseValue: invoice.remiseValue ?? 0,
        remiseAvantTVA: invoice.remiseAvantTVA ?? true,
        notes: invoice.notes ?? '',
        conditions: invoice.conditions ?? ''
      });
      this.setLines(invoice.lignes);
    } else {
      this.currentId = null;
      const numero = await this.store.getNextInvoiceNumber();
      this.form.patchValue({
        numero,
        date: new Date().toISOString().slice(0, 10),
        remiseType: 'montant',
        remiseValue: 0,
        remiseAvantTVA: true
      });
      this.addLine();
    }

    this.form.valueChanges
      .pipe(startWith(this.form.getRawValue()), takeUntil(this.destroy$))
      .subscribe(() => this.updateTotals());
  }

  ngOnDestroy(): void {
    this.destroy$.next();
    this.destroy$.complete();
  }

  addLine(): void {
    this.lignes.push(this.createLine());
  }

  removeLine(index: number): void {
    if (this.lignes.length <= 1) {
      return;
    }
    this.lignes.removeAt(index);
  }

  lineHT(index: number): number {
    const line = this.normalizeLine(this.lignes.at(index).value as InvoiceLine);
    return this.calc.lineHT(line);
  }

  lineTTC(index: number): number {
    const line = this.normalizeLine(this.lignes.at(index).value as InvoiceLine);
    return this.calc.lineTTC(line);
  }

  async save(goToPreview: boolean): Promise<void> {
    this.numeroConflict = false;

    if (this.form.invalid) {
      this.form.markAllAsTouched();
      return;
    }

    const invoice = this.buildInvoice();
    const unique = await this.store.isNumeroUnique(invoice.numero, invoice.id);
    if (!unique) {
      this.numeroConflict = true;
      return;
    }

    await this.store.save(invoice);
    if (goToPreview) {
      this.router.navigate(['/invoices', invoice.id, 'preview']);
    } else {
      this.router.navigate(['/invoices']);
    }
  }

  cancel(): void {
    this.router.navigate(['/invoices']);
  }

  private updateTotals(): void {
    const invoice = this.buildInvoice();
    this.totals = this.calc.totals(invoice);
  }

  private setLines(lines: InvoiceLine[]): void {
    this.lignes.clear();
    lines.forEach((line) => this.lignes.push(this.createLine(line)));
    if (lines.length === 0) {
      this.addLine();
    }
  }

  private createLine(line?: InvoiceLine): ReturnType<FormBuilder['group']> {
    return this.fb.group({
      id: [line?.id ?? this.createId()],
      designation: [line?.designation ?? '', Validators.required],
      unite: [line?.unite ?? '', Validators.required],
      quantite: [line?.quantite ?? 0, [Validators.required, Validators.min(0)]],
      prixUnitaire: [line?.prixUnitaire ?? 0, [Validators.required, Validators.min(0)]],
      tvaRate: [line?.tvaRate ?? 19, [Validators.required, Validators.min(0)]]
    });
  }

  private buildInvoice(): Invoice {
    const raw = this.form.getRawValue();

    return {
      id: this.currentId ?? this.createId(),
      numero: (raw.numero ?? '').trim(),
      date: (raw.date ?? '').trim(),
      client: {
        nom: (raw.client?.nom ?? '').trim(),
        adresse: (raw.client?.adresse ?? '').trim(),
        tel: (raw.client?.tel ?? '').trim(),
        mf: (raw.client?.mf ?? '').trim(),
        email: (raw.client?.email ?? '').trim()
      },
      lignes: (raw.lignes ?? []).map((line: InvoiceLine) => this.normalizeLine(line)),
      remiseType: (raw.remiseType ?? 'montant').trim() as RemiseType,
      remiseValue: Number(raw.remiseValue) || 0,
      remiseAvantTVA: raw.remiseAvantTVA ?? true,
      notes: raw.notes ?? '',
      conditions: raw.conditions ?? ''
    };
  }

  private normalizeLine(line: InvoiceLine): InvoiceLine {
    return {
      ...line,
      quantite: Number(line.quantite) || 0,
      prixUnitaire: Number(line.prixUnitaire) || 0,
      tvaRate: Number(line.tvaRate) || 0
    };
  }

  private createId(): string {
    return globalThis.crypto?.randomUUID?.() ?? `inv_${Date.now()}_${Math.random().toString(16).slice(2)}`;
  }
}
<section class="form-header">
  <div>
    <h1>{{ isEdit ? 'Modifier la facture' : 'Nouvelle facture' }}</h1>
    <p>Les montants sont recalculés en temps réel.</p>
  </div>
  <div class="form-header-actions">
    <a class="btn ghost" routerLink="/invoices">Retour liste</a>
  </div>
</section>

<form class="form-grid" [formGroup]="form">
  <section class="card">
    <h2>Informations facture</h2>
    <div class="grid-3">
      <label class="field">
        <span>Numéro</span>
        <input class="input" formControlName="numero" type="text">
        <span class="error" *ngIf="numeroConflict">Ce numéro existe déjà.</span>
      </label>
      <label class="field">
        <span>Date</span>
        <input class="input" formControlName="date" type="date">
      </label>
      <div class="field">
        <span>Statut</span>
        <div class="tag">{{ isEdit ? 'Brouillon' : 'Nouvelle' }}</div>
      </div>
    </div>
  </section>

  <section class="card">
    <h2>Client</h2>
    <div formGroupName="client" class="grid-2">
      <label class="field">
        <span>Nom</span>
        <input class="input" formControlName="nom" type="text">
      </label>
      <label class="field">
        <span>Téléphone</span>
        <input class="input" formControlName="tel" type="text">
      </label>
      <label class="field">
        <span>Adresse</span>
        <textarea class="input" formControlName="adresse" rows="3"></textarea>
      </label>
      <div class="stack">
        <label class="field">
          <span>MF</span>
          <input class="input" formControlName="mf" type="text">
        </label>
        <label class="field">
          <span>Email</span>
          <input class="input" formControlName="email" type="email">
        </label>
      </div>
    </div>
  </section>

  <section class="card">
    <div class="section-head">
      <h2>Lignes produits</h2>
      <button type="button" class="btn outline" (click)="addLine()">Ajouter ligne</button>
    </div>
    <div class="lines">
      <div class="line-row line-head">
        <div>Désignation</div>
        <div>Unité</div>
        <div>Qté</div>
        <div>PU</div>
        <div>TVA %</div>
        <div>HT</div>
        <div>TTC</div>
        <div></div>
      </div>
      <div class="line-row" *ngFor="let line of lignes.controls; let i = index" [formGroupName]="i">
        <input class="input" formControlName="designation" placeholder="Profilé aluminium 6063">
        <input class="input" formControlName="unite" placeholder="m">
        <input class="input" formControlName="quantite" type="number" min="0" step="0.01">
        <input class="input" formControlName="prixUnitaire" type="number" min="0" step="0.01">
        <input class="input" formControlName="tvaRate" type="number" min="0" step="0.01">
        <div class="amount">{{ lineHT(i) | number:'1.2-2' }}</div>
        <div class="amount">{{ lineTTC(i) | number:'1.2-2' }}</div>
        <button type="button" class="btn danger" (click)="removeLine(i)">Supprimer</button>
      </div>
    </div>
  </section>

  <section class="card">
    <h2>Remise</h2>
    <div class="grid-3">
      <label class="field">
        <span>Type</span>
        <select class="input" formControlName="remiseType">
          <option value="montant">Montant</option>
          <option value="pourcentage">Pourcentage</option>
        </select>
      </label>
      <label class="field">
        <span>Valeur</span>
        <input class="input" type="number" min="0" step="0.01" formControlName="remiseValue">
      </label>
      <label class="field checkbox">
        <input type="checkbox" formControlName="remiseAvantTVA">
        <span>Appliquer la remise avant TVA</span>
      </label>
    </div>
  </section>

  <section class="card">
    <h2>Notes & Conditions</h2>
    <div class="grid-2">
      <label class="field">
        <span>Notes</span>
        <textarea class="input" formControlName="notes" rows="4"></textarea>
      </label>
      <label class="field">
        <span>Conditions</span>
        <textarea class="input" formControlName="conditions" rows="4"></textarea>
      </label>
    </div>
  </section>

  <section class="card totals">
    <h2>Totaux</h2>
    <div class="totals-grid">
      <div>
        <span>Total HT</span>
        <strong>{{ totals.totalHT | number:'1.2-2' }} DT</strong>
      </div>
      <div>
        <span>Total TVA</span>
        <strong>{{ totals.totalTVA | number:'1.2-2' }} DT</strong>
      </div>
      <div>
        <span>Remise</span>
        <strong>- {{ totals.remise | number:'1.2-2' }} DT</strong>
      </div>
      <div>
        <span>Total TTC</span>
        <strong class="accent">{{ totals.totalTTC | number:'1.2-2' }} DT</strong>
      </div>
    </div>
  </section>

  <div class="form-actions">
    <button class="btn ghost" type="button" (click)="cancel()">Annuler</button>
    <button class="btn outline" type="button" (click)="save(false)">Enregistrer</button>
    <button class="btn primary" type="button" (click)="save(true)">Enregistrer & Aperçu</button>
  </div>
</form>
